const payload = $json.body ?? $json;
const requiredFields = ['source', 'eventType', 'severity', 'summary'];

const missing = requiredFields.filter((field) => {
  const value = payload[field];
  return value === undefined || value === null || String(value).trim() === '';
});

if (missing.length > 0) {
  throw new Error(`Invalid payload: missing required fields (${missing.join(', ')})`);
}

const severity = String(payload.severity).toLowerCase().trim();
const allowed = ['info', 'low', 'medium', 'high', 'critical'];
if (!allowed.includes(severity)) {
  throw new Error(`Invalid severity: '${payload.severity}'. Allowed: ${allowed.join(', ')}`);
}

const correlationId = payload.correlationId && String(payload.correlationId).trim()
  ? String(payload.correlationId).trim()
  : `${Date.now()}-${Math.random().toString(36).slice(2, 10)}`;

return [{
  json: {
    source: String(payload.source).trim(),
    eventType: String(payload.eventType).trim(),
    severity,
    summary: String(payload.summary).trim(),
    details: payload.details ? String(payload.details) : '',
    metadata: payload.metadata && typeof payload.metadata === 'object' ? payload.metadata : {},
    occurredAt: payload.occurredAt ? String(payload.occurredAt) : new Date().toISOString(),
    receivedAt: new Date().toISOString(),
    correlationId,
    escalate: severity === 'high' || severity === 'critical'
  }
}];
